-- db/rollback_feeder_class_recipes.sql [T2.1-4 rollback]: restore cards 16/17 to the pre-migration name_contains/types roster_spec.

UPDATE card_fill_recipe SET roster_spec='{"slots": [{"emit": {"legend": {"slot": "trend.view.legend", "ndigits": 0, "key_field": "id", "value_field": "value"}, "totals": {"slot": "trend.view.totals", "ndigits": 0, "label_field": "label", "value_field": "value"}, "insight": {"slot": "trend.view.insight", "unit": "kWh", "ndigits": 0}, "total_legend": {"slot": "trend.view.totalLegend", "ndigits": 0, "key_field": "id", "value_field": "value"}, "selected_label": {"slot": "trend.view.selectedLabel"}}, "mode": "series", "slot": "trend.view.points", "scope": "members", "columns": [{"r": 0, "key": "active", "kind": "energy_delta", "column": "active_energy_import_kwh", "reduce": "sum_magnitude"}, {"r": 0, "key": "reactive", "kind": "energy_delta", "column": "reactive_energy_import_kvarh", "reduce": "sum_magnitude"}, {"r": 0, "key": "ups", "kind": "energy_delta", "match": {"types": ["ups"]}, "column": "active_energy_import_kwh", "reduce": "sum_magnitude"}, {"r": 0, "key": "bpdp", "kind": "energy_delta", "match": {"name_contains": ["bpdb", "bpdp"]}, "column": "active_energy_import_kwh", "reduce": "sum_magnitude"}, {"r": 0, "key": "hhf", "kind": "energy_delta", "match": {"types": ["hhf"], "name_contains": ["hhf"]}, "column": "active_energy_import_kwh", "reduce": "sum_magnitude"}], "derived": {"rated": {"v": null, "op": "const"}, "total": {"r": 0, "of": ["active", "reactive"], "op": "sum"}, "contracted": {"v": null, "op": "const"}}, "sampling": "day", "label_fmt": "MMM DD", "label_key": "label", "total_key": "total", "role_filter": "load"}], "coverage_attach": "widgets._coverage"}'::jsonb WHERE card_id=16;

UPDATE card_fill_recipe SET roster_spec='{"slots": [{"why": "FeederDemandPoint FE contract = {label, ups, bpdp, hhf}. Each series folds ONLY its own feeder group''s real panel-317 members (Sigma active_power_total_kw, hourly, power->sum_magnitude): ups = the 6 GIC UPS feeders (11/12/13 live + 23/24/25 dark-but-present), bpdp = the 2 BPDB feeders (16 live + 20 dark). HHF matches NO member on this panel (no HHF feeder in the 317 roster) so every point''s hhf leaf honest-nulls -- never the panel Sigma misattributed to a fixture line. Points align on the UNION of real hourly buckets; the label carries the real bucket time. Legend scalars refresh from each series'' OWN last real bucket (hhf -> null).", "mode": "series_split", "slot": "demand.view.points", "scope": "members", "t_fmt": "DD HH:MM", "t_key": "label", "column": "active_power_total_kw", "legend": {"slot": "demand.view.legend", "ndigits": 0, "key_field": "id", "value_field": "value"}, "reduce": "sum_magnitude", "series": [{"key": "ups", "match": {"types": ["ups"], "name_contains": ["ups"]}}, {"key": "bpdp", "match": {"name_contains": ["bpdb", "bpdp"]}}, {"key": "hhf", "match": {"name_contains": ["hhf"]}}], "ndigits": 2, "sampling": "hourly", "null_value": null, "role_filter": "load"}, {"why": "Worst-Peak tile = MAX of the panel-317 members'' OWN rolled active-power trend (Sigma active_power_total_kw, hourly, load feeders). A peak is a series max, never a latest-row read; the panel device 317 has no electrical of its own so the value must come from the member roll-up. Writes stats.0.value=peak and stats.0.sub=''at <peak bucket>''; main slot targets a non-data token so nothing is overwritten. Modeled on the working card-10 trend.bottomStats peak exemplar.", "mode": "series", "slot": "demand.view.stats._peak_scratch", "scope": "members", "stats": [{"r": 1, "op": "maximum", "why": "Worst Peak kW + its bucket time", "slot": "demand.view.stats.0.value", "at_fmt": "DD HH:MM", "at_slot": "demand.view.stats.0.sub", "at_prefix": "at "}], "column": "active_power_total_kw", "points": true, "reduce": "sum_magnitude", "sampling": "hourly", "value_key": null, "role_filter": "load"}], "coverage_attach": null}'::jsonb WHERE card_id=17;

